@dataclass
class PathSettings:
    raw_daily_dir: Path = Path("data/daily")
    merged_parquet: Path = Path("data/market_daily.parquet")

    def resolve(self, root: Path) -> "PathSettings":
        for field_name in ("raw_daily_dir", "merged_parquet"):
            value = getattr(self, field_name)
            setattr(self, field_name, (root / value).resolve() if not value.is_absolute() else value)
        return self

    def ensure(self) -> None:
        self.raw_daily_dir.mkdir(parents=True, exist_ok=True)
        self.merged_parquet.parent.mkdir(parents=True, exist_ok=True)


@dataclass
class AppConfig:
    paths: PathSettings = field(default_factory=PathSettings)
    logging: LoggingSettings = field(default_factory=LoggingSettings)
    download: DownloadSettings = field(default_factory=DownloadSettings)

    def resolve(self, root: Path = ROOT_DIR) -> "AppConfig":
        self.paths.resolve(root)
        self.paths.ensure()
        return self


def canonicalize_raw_frame(frame: pd.DataFrame, symbol_hint: str) -> pd.DataFrame:
    if frame.empty:
        return pd.DataFrame()
    normalized = frame.copy()
    if "date" in normalized.columns:
        normalized["date"] = pd.to_datetime(normalized["date"], errors="coerce")
        normalized = normalized.dropna(subset=["date"])
    if "symbol" not in normalized.columns:
        normalized["symbol"] = symbol_hint.upper()
    normalized.sort_values("date", inplace=True)
    normalized = normalized.drop_duplicates(subset=["date"], keep="last")
    return normalized.reset_index(drop=True)


def merge_daily_parquets(config: AppConfig, force: bool = True) -> dict[str, int | str]:
    source_dir = config.paths.raw_daily_dir
    output_path = config.paths.merged_parquet
    output_path.parent.mkdir(parents=True, exist_ok=True)
    if output_path.exists() and not force:
        LOGGER.info("Merged parquet already exists, skipping rebuild path=%s", output_path)
        return {"symbols": 0, "rows": 0, "path": str(output_path)}

    file_paths = sorted(source_dir.glob("*.parquet"))
    if not file_paths:
        raise RuntimeError(f"No raw parquet files found in {source_dir}")
    LOGGER.info(
        "Merging raw parquet files source_dir=%s output_path=%s files=%s force=%s",
        source_dir,
        output_path,
        len(file_paths),
        force,
    )
    if output_path.exists():
        output_path.unlink()

    merged_frames: list[pd.DataFrame] = []
    total_rows = 0
    total_symbols = 0
    for index, path in enumerate(file_paths, start=1):
        frame = pd.read_parquet(path)
        normalized = canonicalize_raw_frame(frame, path.stem)
        if normalized.empty:
            LOGGER.debug("Skipping empty normalized parquet path=%s", path)
            continue
        merged_frames.append(normalized)
        total_rows += len(normalized)
        total_symbols += 1
        if index % 200 == 0 or index == len(file_paths):
            LOGGER.info(
                "Merge progress processed_files=%s/%s merged_symbols=%s merged_rows=%s",
                index,
                len(file_paths),
                total_symbols,
                total_rows,
            )
    if not merged_frames:
        raise RuntimeError(f"No usable parquet rows found in {source_dir}")
    merged = pd.concat(merged_frames, ignore_index=True, sort=False)
    merged.to_parquet(output_path, index=False)
    LOGGER.info("Merged parquet ready path=%s symbols=%s rows=%s", output_path, total_symbols, total_rows)
    return {"symbols": total_symbols, "rows": total_rows, "path": str(output_path)}


def build_juliang_sign(params: Dict[str, object], api_key: str) -> str:
    canonical = [
        f"{key}={params[key]}"
        for key in sorted(params)
        if params[key] is not None and str(params[key]).strip() != ""
    ]
    raw = "&".join(canonical) + f"&key={api_key}"
    return hashlib.md5(raw.encode("utf-8")).hexdigest()


